class BiometricAuthManager {
    static let shared = BiometricAuthManager()
    
    private let context = LAContext()
    private let keychainService = "com.yourapp.biometric"
    private let authenticationKey = "isAuthenticated"
    
    private init() {}
    
    enum BiometricType {
        case none
        case touchID
        case faceID
    }
    
    enum AuthenticationError: Error {
        case biometricNotAvailable
        case biometricNotEnrolled
        case authenticationFailed
        case userCancel
        case userFallback
        case systemCancel
        case passcodeNotSet
        case biometricLockout
        case unknown
        
        var localizedDescription: String {
            switch self {
            case .biometricNotAvailable:
                return "Biometric authentication is not available on this device"
            case .biometricNotEnrolled:
                return "No biometric data is enrolled"
            case .authenticationFailed:
                return "Authentication failed"
            case .userCancel:
                return "User cancelled authentication"
            case .userFallback:
                return "User chose to enter password"
            case .systemCancel:
                return "System cancelled authentication"
            case .passcodeNotSet:
                return "Passcode is not set on device"
            case .biometricLockout:
                return "Too many failed attempts. Please try again later"
            case .unknown:
                return "An unknown error occurred"
            }
        }
    }
    
    func getBiometricType() -> BiometricType {
        let context = LAContext()
        var error: NSError?
        
        guard context.canEvaluatePolicy(.deviceOwnerAuthenticationWithBiometrics, error: &error) else {
            return .none
        }
        
        if #available(iOS 11.0, *) {
            switch context.biometryType {
            case .faceID:
                return .faceID
            case .touchID:
                return .touchID
            case .none:
                return .none
            @unknown default:
                return .none
            }
        } else {
            return .touchID
        }
    }
    
    func canUseBiometrics() -> Bool {
        var error: NSError?
        return context.canEvaluatePolicy(.deviceOwnerAuthenticationWithBiometrics, error: &error)
    }
    
    func authenticateUser(reason: String, completion: @escaping (Result<Bool, AuthenticationError>) -> Void) {
        let context = LAContext()
        context.localizedCancelTitle = "Enter Password"
        context.localizedFallbackTitle = "Use Password"
        
        var error: NSError?
        
        guard context.canEvaluatePolicy(.deviceOwnerAuthenticationWithBiometrics, error: &error) else {
            if let laError = error {
                completion(.failure(mapLAError(laError)))
            } else {
                completion(.failure(.biometricNotAvailable))
            }
            return
        }
        
        context.evaluatePolicy(.deviceOwnerAuthenticationWithBiometrics, localizedReason: reason) { success, error in
            DispatchQueue.main.async {
                if success {
                    self.setAuthenticationStatus(true)
                    completion(.success(true))
                } else {
                    if let laError = error as? LAError {
                        completion(.failure(self.mapLAError(laError)))
                    } else {
                        completion(.failure(.unknown))
                    }
                }
            }
        }
    }
    
    func authenticateWithDevicePasscode(reason: String, completion: @escaping (Result<Bool, AuthenticationError>) -> Void) {
        let context = LAContext()
        context.localizedCancelTitle = "Cancel"
        
        var error: NSError?
        
        guard context.canEvaluatePolicy(.deviceOwnerAuthentication, error: &error) else {
            if let laError = error {
                completion(.failure(mapLAError(laError)))
            } else {
                completion(.failure(.passcodeNotSet))
            }
            return
        }
        
        context.evaluatePolicy(.deviceOwnerAuthentication, localizedReason: reason) { success, error in
            DispatchQueue.main.async {
                if success {
                    self.setAuthenticationStatus(true)
                    completion(.success(true))
                } else {
                    if let laError = error as? LAError {
                        completion(.failure(self.mapLAError(laError)))
                    } else {
                        completion(.failure(.unknown))
                    }
                }
            }
        }
    }
    
    private func mapLAError(_ error: Error) -> AuthenticationError {
        guard let laError = error as? LAError else {
            return .unknown
        }
        
        switch laError.code {
        case .authenticationFailed:
            return .authenticationFailed
        case .userCancel:
            return .userCancel
        case .userFallback:
            return .userFallback
        case .systemCancel:
            return .systemCancel
        case .passcodeNotSet:
            return .passcodeNotSet
        case .biometryNotAvailable:
            return .biometricNotAvailable
        case .biometryNotEnrolled:
            return .biometricNotEnrolled
        case .biometryLockout:
            return .biometricLockout
        default:
            return .unknown
        }
    }
    
    func setAuthenticationStatus(_ isAuthenticated: Bool) {
        let query: [String: Any] = [
            kSecClass as String: kSecClassGenericPassword,
            kSecAttrService as String: keychainService,
            kSecAttrAccount as String: authenticationKey
        ]
        
        SecItemDelete(query as CFDictionary)
        
        if isAuthenticated {
            let data = Data("authenticated".utf8)
            let addQuery: [String: Any] = [
                kSecClass as String: kSecClassGenericPassword,
                kSecAttrService as String: keychainService,
                kSecAttrAccount as String: authenticationKey,
                kSecValueData as String: data,
                kSecAttrAccessible as String: kSecAttrAccessibleWhenUnlockedThisDeviceOnly
            ]
            
            SecItemAdd(addQuery as CFDictionary, nil)
        }
    }
    
    func isAuthenticated() -> Bool {
        let query: [String: Any] = [
            kSecClass as String: kSecClassGenericPassword,
            kSecAttrService as String: keychainService,
            kSecAttrAccount as String: authenticationKey,
            kSecReturnData as String: true,
            kSecMatchLimit as String: kSecMatchLimitOne
        ]
        
        var result: AnyObject?
        let status = SecItemCopyMatching(query as CFDictionary, &result)
        
        return status == errSecSuccess
    }
    
    func clearAuthenticationStatus() {
        setAuthenticationStatus(false)
    }
    
    func enableBiometricAuthentication(completion: @escaping (Result<Bool, AuthenticationError>) -> Void) {
        let biometricType = getBiometricType()
        let reason: String
        
        switch biometricType {
        case .faceID:
            reason = "Enable Face ID to quickly access your account"
        case .touchID:
            reason = "Enable Touch ID to quickly access your account"
        case .none:
            completion(.failure(.biometricNotAvailable))
            return
        }
        
        authenticateUser(reason: reason, completion: completion)
    }
}

